  'weifang/kite': ('เมืองหลวงแห่งว่าว', 'เมืองหลวงแห่งว่าวของโลกที่จัดเทศกาลนานาชาติขึ้นทุกเดือนเมษายนจนเต็มท้องฟ้า'),
  'weifang/woodprint': ('ภาพพิมพ์ไม้หยางเจียปู้', 'หมู่บ้านแห่งนี้สืบทอดการทำภาพพิมพ์ไม้สำหรับเทศกาลตรุษจีนมานานกว่า 600 ปี'),
  'weifang/dragon': ('ว่าวมังกร', 'ว่าวมังกรที่มีความยาวกว่าร้อยเมตรถือเป็นไฮไลท์สำคัญของเทศกาลว่าว'),
  'weifang/radish': ('หัวไชเท้าเหวยฟาง', 'หัวไชเท้าสีเขียวที่สามารถทานสดได้เหมือนผลไม้ถือเป็นของดีขึ้นชื่อของเมืองนี้'),
  'dezhou/chicken': ('ไก่ตุ๋นเต๋อโจว', 'ไก่ตุ๋นเนื้อนุ่มจนหลุดจากกระดูกเมนูนี้เคยเป็นอาหารที่ถวายแด่จักรพรรดิในสมัยก่อน'),
  'dezhou/sun': ('หุบเขาพลังงานแสงอาทิตย์', 'ที่นี่เป็นที่ตั้งของหนึ่งในศูนย์วิจัยและพัฒนาพลังงานแสงอาทิตย์ที่ใหญ่ที่สุดในโลก'),
  'dezhou/grapes': ('สวนเมลอนและองุ่น', 'พื้นที่ราบอันอุดมสมบูรณ์แห่งนี้เต็มไปด้วยเมลอนและองุ่นมากมายในช่วงฤดูร้อน'),
  'dezhou/train': ('ท่าเรือคลองขุด', 'ในอดีตที่นี่เคยเป็นท่าเรือขนส่งธัญพืชที่คึกคักที่สุดแห่งหนึ่งบนเส้นทางคลองขุดต้ายวิ่นเหอ'),
  'xuzhou/stone': ('ภาพสลักหินสมัยราชวงศ์ฮั่น', 'แผ่นหินจากสุสานสมัยราชวงศ์ฮั่นที่บอกเล่าเรื่องราววิถีชีวิตของผู้คนเมื่อ 2,000 ปีก่อน'),
  'xuzhou/terracotta': ('กองทัพทหารดินเผา', 'มีการขุดพบกองทัพทหารดินเผาที่มีขนาดเล็กกว่าแต่เก่าแก่กว่าที่อื่นในเมืองนี้'),
  'xuzhou/lake': ('ทะเลสาบอวิ๋นหลง', 'พื้นที่ริมทะเลสาบอวิ๋นหลงเปรียบเสมือนปอดสีเขียวของเมืองที่ผู้คนนิยมมาพักผ่อน'),
  'xuzhou/skewer': ('วัฒนธรรมปิ้งย่าง', 'เมืองนี้ได้ชื่อว่าเป็นเมืองหลวงแห่งปิ้งย่างของจีน โดยมีเนื้อแกะเสียบไม้ย่างบนเตาถ่านให้บริการตลอดทั้งคืน'),
  'zhenjiang/vinegar': ('จิ๊กโฉ่วเจิ้นเจียง', 'น้ำส้มสายชูดำจากข้าวเหนียวที่มีชื่อเสียงที่สุดของจีน ซึ่งหมักบ่มสืบทอดกันมานานกว่า 1,400 ปี'),
  'zhenjiang/temple': ('วัดจินซาน', 'วัดเก่าแก่ริมแม่น้ำที่เป็นสถานที่ในตำนานเรื่องนางพญางูขาว'),
  'zhenjiang/pot': ('บะหมี่ฝาหม้อ', 'บะหมี่ฝาหม้อที่ปรุงด้วยการวางฝาหม้อปิดทับลงไปในน้ำซุปเป็นเมนูอาหารเช้าขึ้นชื่อของท้องถิ่น'),
  'zhenjiang/bridge': ('ริมฝั่งแม่น้ำแยงซี', 'พื้นที่ริมฝั่งแม่น้ำที่รายล้อมไปด้วยสวนสาธารณะและเส้นทางเดินชมวิวท่ามกลางภูเขาสามลูก'),
  'jiaxing/zongzi': ('บ๊ะจ่าง', 'เมืองนี้ถือเป็นเมืองหลวงแห่งบ๊ะจ่าง ซึ่งเป็นข้าวเหนียวห่อใบไผ่ที่มีชื่อเสียงโด่งดัง'),
  'jiaxing/boat': ('เรือแดงแห่งทะเลสาบหนานหู', 'ในปี ค.ศ. 1921 การประชุมสมัชชาใหญ่พรรคคอมมิวนิสต์ครั้งแรกได้จัดขึ้นบนเรือลำหนึ่งในทะเลสาบแห่งนี้'),
  'jiaxing/silk': ('เมืองแห่งผ้าไหม', 'ผ้าไหมเจียงหนานถูกทอขึ้นในเมืองริมคลองแห่งนี้มานานหลายศตวรรษ'),
  'jiaxing/canal': ('เมืองน้ำอูเจิ้น', 'สัมผัสบรรยากาศเมืองริมน้ำที่มีสะพานหินและโคมไฟประดับประดาด้วยการล่องเรือ'),
  'lishui/mountains': ('ยอดเขาเขียวขจี', 'พื้นที่ที่เต็มไปด้วยภูเขามากที่สุดในเจ้อเจียง ซึ่งมีหมู่บ้านบนนาขั้นบันไดที่สูงเสียดฟ้า'),
  'lishui/camera': ('สวรรค์ของช่างภาพ', 'นาขั้นบันไดท่ามกลางสายหมอกเป็นหนึ่งในทิวทัศน์ที่ถูกถ่ายภาพมากที่สุดในจีน'),
  'lishui/mushroom': ('ดินแดนแห่งเห็ด', 'อำเภอชิงหยวนถือเป็นแหล่งกำเนิดของการเพาะเห็ดที่สำคัญที่สุดของโลก'),
  'lishui/raft': ('ล่องแพไม้ไผ่', 'ล่องแพไม้ไผ่ไปตามแม่น้ำโอวเจียงเพื่อชมความงามของหุบเขาเขียวขจี'),
  'anqing/opera': ('งิ้วหวงเหมย', 'ศิลปะการแสดงงิ้วท้องถิ่นที่เป็นที่รักมากที่สุดของจีนมีต้นกำเนิดมาจากที่นี่'),
  'anqing/pagoda': ('เจดีย์เจิ้นเฟิง', 'เจดีย์เก่าแก่อายุกว่า 400 ปีริมแม่น้ำแยงซีที่ได้รับการขนานนามว่าเป็นประภาคารแห่งแรกของแม่น้ำ'),
  'anqing/tea': ('ชาเยว่ซี', 'ชาเขียวรสเลิศที่มีกลิ่นหอมละมุนปลูกอยู่บนไหล่เขาต้าเปี๋ย'),
  'anqing/sail': ('ประตูแม่น้ำ', 'เมืองท่าสำคัญริมแม่น้ำแยงซีในมณฑลอันฮุย ซึ่งชื่อเมืองมีความหมายว่าการเฉลิมฉลองอย่างสงบสุข'),
  'ganzhou/orange': ('ส้มนาเวลก้านหนาน', 'ส้มนาเวลที่หวานที่สุดในจีนเติบโตได้ดีในดินสีแดงของพื้นที่แห่งนี้'),
  'ganzhou/house': ('บ้านดินชาวฮากกา', 'วัฒนธรรมชาวฮากกาสืบทอดมายาวนานหลายศตวรรษภายในบ้านป้อมปราการทรงกลม'),
  'ganzhou/pavilion': ('ศาลาอวี้กู', 'ศาลาที่กวีสมัยราชวงศ์ซ่งเคยพรรณนาถึงความงาม โดยตั้งอยู่บนจุดที่แม่น้ำสองสายมาบรรจบกัน'),
  'ganzhou/star': ('การเดินทัพทางไกล', 'เมืองนี้เป็นจุดเริ่มต้นของการเดินทัพทางไกลของกองทัพแดง'),
  'putian/shrine': ('ศาลเจ้าแม่หม่าโจ้ว', 'เจ้าแม่หม่าโจ้วเทพีผู้คุ้มครองชาวเรือประสูติที่นี่ และมีศาลเจ้าหลักตั้งอยู่บนเกาะเหมยโจว'),
  'putian/lychee': ('สวนลิ้นจี่', 'ต้นลิ้นจี่ที่มีอายุเก่าแก่กว่าพันปีทำให้เมืองนี้ได้รับฉายาว่าเป็นดินแดนแห่งลิ้นจี่'),
  'putian/shoe': ('เมืองหลวงแห่งรองเท้า', 'สัดส่วนการผลิตรองเท้ากีฬาจำนวนมหาศาลของโลกมาจากโรงงานในเมืองนี้'),
  'putian/wave': ('เกาะเหมยโจว', 'เกาะที่เดินทางไปถึงได้ด้วยเรือเฟอร์รี่แห่งนี้มีชื่อเสียงจากชายหาดที่สวยงามและเทศกาลงานวัด'),
  'mudanjiang/snow': ('หมู่บ้านหิมะ', 'หมู่บ้านในเทพนิยายที่ถูกปกคลุมด้วยหิมะหนานุ่มและส่องประกายงดงามในช่วงฤดูหนาว'),
  'mudanjiang/lake': ('ทะเลสาบจิ้งป๋อ', 'ทะเลสาบที่เกิดจากการระเบิดของภูเขาไฟซึ่งมีน้ำตกเตี้ยวสุ่ยโหลวที่ยังคงไหลแม้ในฤดูหนาว'),
  'mudanjiang/tiger': ('สวนเสือไซบีเรีย', 'หนึ่งในเขตรักษาพันธุ์เสือไซบีเรียที่ใหญ่ที่สุดในโลก'),
  'mudanjiang/ski': ('ฤดูกาลเล่นสกี', 'ฤดูหนาวที่มีหิมะตกยาวนานทำให้ภูมิภาคนี้เป็นจุดหมายปลายทางที่นักสกีทุกคนต้องมาเยือน'),
  'changzhou/dino': ('สวนสนุกไดโนเสาร์', 'สวนสนุกไดโนเสาร์ที่มีชื่อเสียงที่สุดของจีนถือเป็นสัญลักษณ์แห่งความสุขของครอบครัวในเมืองนี้'),
  'changzhou/pagoda': ('เจดีย์เทียนหนิง', 'เจดีย์ที่สูงที่สุดในโลกด้วยความสูง 153 เมตรตั้งตระหง่านอยู่ใจกลางเมือง'),
  'changzhou/comb': ('งานหัตถกรรมหวี', 'หวีจากฉางโจวที่มีประวัติศาสตร์ยาวนานนับพันปีเคยเป็นของขวัญล้ำค่าที่ใช้ถวายในวัง'),
  'changzhou/canal': ('คลองขุดต้ายวิ่นเหอ', 'ริมฝั่งคลองเป็นจุดเดินเล่นยอดนิยมที่เต็มไปด้วยย่านเมืองเก่าและแสงไฟยามค่ำคืน'),
  'shaoxing/wine': ('เหล้าเส้าซิง', 'เหล้าข้าวสีเหลืองที่มีชื่อเสียงในการปรุงอาหารจีนแห่งนี้มีการหมักบ่มมานานนับพันปี'),
  'shaoxing/bridge': ('สะพานหินโบราณ', 'เมืองเส้าซิงที่เต็มไปด้วยลำคลองยังคงอนุรักษ์สะพานหินโค้งไว้หลายร้อยแห่ง'),
  'shaoxing/pen': ('แหล่งกำเนิดอักษรวิจิตร', 'ศาลาหลานถิงของปรมาจารย์หวังซีจือถือเป็นสถานที่ศักดิ์สิทธิ์ของศิลปะการเขียนพู่กันจีน'),
  'shaoxing/boat': ('เรืออูเผิง', 'เรือพายหลังคาดำที่ใช้เท้าถีบเป็นพาหนะสุดคลาสสิกในการล่องไปตามลำคลอง'),
  'bengbu/shell': ('ท่าเรือไข่มุก', 'ชื่อเมืองมีความหมายว่าท่าเรือหอย ซึ่งในอดีตเคยมีชื่อเสียงโด่งดังจากการผลิตไข่มุกแห่งแม่น้ำหวย'),
  'bengbu/train': ('สถานีรถไฟเปิ่งปู้', 'เมืองนี้เติบโตขึ้นจากการเป็นจุดเชื่อมต่อสำคัญของเส้นทางรถไฟสายเหนือ-ใต้ที่ตัดผ่านแม่น้ำหวย'),
  'bengbu/river': ('แม่น้ำหวย', 'แม่น้ำสายสำคัญที่เป็นเส้นแบ่งเขตทางภูมิศาสตร์ระหว่างจีนเหนือและจีนใต้'),
  'bengbu/blossom': ('เทศกาลชมดอกไม้', 'สวนสาธารณะริมแม่น้ำจะเต็มไปด้วยสีสันของเทศกาลชมดอกไม้ในช่วงฤดูใบไม้ผลิ'),
  'jiujiang/mountain': ('เขาหลูซาน', 'ยอดเขาที่ปกคลุมด้วยสายหมอกแห่งนี้ได้รับการขึ้นทะเบียนเป็นมรดกโลกและเป็นแรงบันดาลใจให้กวีและจิตรกรมากมาย'),
  'jiujiang/tea': ('ชาอวิ๋นอู้', 'ชาจากบนเขาหลูซานที่มีรสชาติละมุนและถือเป็นหนึ่งในชาชั้นเลิศของจีน'),
  'jiujiang/lake': ('ทะเลสาบโผหยาง', 'ทะเลสาบน้ำจืดที่ใหญ่ที่สุดในจีนและเป็นแหล่งอาศัยของนกกระเรียนนับพันตัวในช่วงฤดูหนาว'),
  'jiujiang/scroll': ('เมืองแห่งกวี', 'ประตูเมืองริมน้ำแห่งนี้เคยเป็นสถานที่ที่กวีเอกอย่างไป๋จวีอี้และซูซื่อเคยมาพำนักและรังสรรค์บทกวีไว้'),
  'quanzhou/ship': ('เส้นทางสายไหมทางทะเล', 'เมืองท่าที่ยิ่งใหญ่ที่สุดในยุคกลางที่มาร์โก โปโลเคยมาเยือนและได้รับการขึ้นทะเบียนเป็นมรดกโลก'),
  'quanzhou/mosque': ('มัสยิดชิงจิ้ง', 'มัสยิดหินเก่าแก่ที่สร้างขึ้นในปี ค.ศ. 1009 และถือเป็นหนึ่งในมัสยิดที่เก่าแก่ที่สุดในจีน'),
  'quanzhou/puppet': ('หุ่นเชิดสาย', 'ศิลปะการแสดงหุ่นเชิดสายของฉวนโจวเป็นประเพณีบนเวทีที่มีประวัติศาสตร์ยาวนานกว่าพันปี'),
  'quanzhou/tea': ('ชาทิกวนอิม', 'ชาอูหลงจากเมืองอันซีที่อยู่ใกล้เคียง ซึ่งเป็นที่รู้จักไปทั่วโลกในชื่อชาเจ้าแม่กวนอิมเหล็ก'),
  'beijing/great-wall': ('กำแพงเมืองจีน', 'สิ่งก่อสร้างที่ยาวที่สุดในโลกซึ่งสร้างขึ้นเพื่อป้องกันพรมแดนทางเหนือ โดยด่านปาต้าหลิ่งใกล้กรุงปักกิ่งเป็นจุดที่ได้รับความนิยมมากที่สุด'),
  'beijing/temple': ('หอฟ้าเทียนถาน', 'สถานที่ที่จักรพรรดิในอดีตใช้ประกอบพิธีบวงสรวงสวรรค์เพื่อขอให้บ้านเมืองอุดมสมบูรณ์ โดดเด่นด้วยสถาปัตยกรรมหลังคาทรงกลมสีน้ำเงินที่สร้างโดยไม่ใช้ตะปูแม้แต่ตัวเดียว'),
  'beijing/pagoda': ('เจดีย์เทียนหนิง', 'เจดีย์อิฐ 13 ชั้นจากสมัยราชวงศ์เหลียวที่มีความเก่าแก่และเป็นพยานหลักฐานทางประวัติศาสตร์นับพันปีของกรุงปักกิ่ง'),
  'beijing/opera': ('งิ้วปักกิ่ง', 'ศิลปะการแสดงดั้งเดิมที่ผสมผสานทั้งการร้อง การพูด และศิลปะการต่อสู้ โดยการแต่งหน้าแบบเหลียนผู่จะช่วยบ่งบอกลักษณะนิสัยของตัวละครได้อย่างชัดเจน'),
};
